import { useState } from 'react';

const WEEKLY = [
  { day: 'Mon', orders: 28, revenue: 6800 },
  { day: 'Tue', orders: 34, revenue: 8200 },
  { day: 'Wed', orders: 22, revenue: 5400 },
  { day: 'Thu', orders: 41, revenue: 9800 },
  { day: 'Fri', orders: 56, revenue: 13200 },
  { day: 'Sat', orders: 68, revenue: 16400 },
  { day: 'Sun', orders: 49, revenue: 11600 },
];

const TOP_ITEMS = [
  { name: 'Chicken Biryani',  orders: 89, revenue: 22250, emoji: '🍛' },
  { name: 'Butter Chicken',   orders: 74, revenue: 20720, emoji: '🍛' },
  { name: 'Paneer Tikka',     orders: 68, revenue: 14960, emoji: '🧀' },
  { name: 'Dal Makhani',      orders: 61, revenue:  9760, emoji: '🍲' },
  { name: 'Garlic Naan',      orders: 112, revenue:  4480, emoji: '🫓' },
];

const SUMMARY = [
  { label: 'This week revenue', value: '₹71,400', change: '+18%', up: true  },
  { label: 'Total orders',       value: '298',     change: '+12%', up: true  },
  { label: 'Avg order value',    value: '₹239',    change: '+5%',  up: true  },
  { label: 'Cancelled orders',   value: '7',       change: '-3%',  up: false },
];

export default function Reports() {
  const [period, setPeriod] = useState('week');
  const maxRevenue  = Math.max(...WEEKLY.map(d => d.revenue));
  const maxOrders   = Math.max(...WEEKLY.map(d => d.orders));
  const maxItemRevenue = Math.max(...TOP_ITEMS.map(i => i.revenue));

  return (
    <div className="flex flex-col gap-5">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-gray-900">Reports & Analytics</h2>
          <p className="text-sm text-gray-500 mt-0.5">Sales performance overview</p>
        </div>
        <div className="flex gap-2 bg-gray-100 p-1 rounded-xl">
          {['week', 'month'].map(p => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              className={`px-4 py-1.5 rounded-lg text-sm font-medium transition-colors capitalize ${
                period === p ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              This {p}
            </button>
          ))}
        </div>
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-2 xl:grid-cols-4 gap-4">
        {SUMMARY.map((s, i) => (
          <div key={i} className="bg-white border border-gray-200 rounded-2xl p-5">
            <p className="text-xs text-gray-500 mb-2">{s.label}</p>
            <p className="text-2xl font-extrabold text-gray-900">{s.value}</p>
            <p className={`text-xs font-medium mt-1 ${s.up ? 'text-green-600' : 'text-red-600'}`}>
              {s.up ? '▲' : '▼'} {s.change} vs last {period}
            </p>
          </div>
        ))}
      </div>

      {/* Charts row */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-5">

        {/* Revenue bar chart */}
        <div className="bg-white border border-gray-200 rounded-2xl p-5">
          <h3 className="font-semibold text-gray-900 mb-5">Daily revenue (₹)</h3>
          <div className="flex items-end gap-3 h-40">
            {WEEKLY.map((d, i) => (
              <div key={i} className="flex-1 flex flex-col items-center gap-1.5">
                <span className="text-xs text-gray-500 font-medium">
                  ₹{Math.round(d.revenue / 1000)}k
                </span>
                <div
                  className="w-full bg-red-500 hover:bg-red-600 rounded-t-lg transition-colors cursor-default"
                  style={{ height: `${(d.revenue / maxRevenue) * 100}%`, minHeight: '4px' }}
                  title={`₹${d.revenue}`}
                />
                <span className="text-xs text-gray-400 font-medium">{d.day}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Orders bar chart */}
        <div className="bg-white border border-gray-200 rounded-2xl p-5">
          <h3 className="font-semibold text-gray-900 mb-5">Daily orders</h3>
          <div className="flex items-end gap-3 h-40">
            {WEEKLY.map((d, i) => (
              <div key={i} className="flex-1 flex flex-col items-center gap-1.5">
                <span className="text-xs text-gray-500 font-medium">{d.orders}</span>
                <div
                  className="w-full bg-blue-500 hover:bg-blue-600 rounded-t-lg transition-colors cursor-default"
                  style={{ height: `${(d.orders / maxOrders) * 100}%`, minHeight: '4px' }}
                  title={`${d.orders} orders`}
                />
                <span className="text-xs text-gray-400 font-medium">{d.day}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Top selling items */}
      <div className="bg-white border border-gray-200 rounded-2xl p-5">
        <h3 className="font-semibold text-gray-900 mb-5">Top selling items this {period}</h3>
        <div className="flex flex-col gap-4">
          {TOP_ITEMS.map((item, i) => (
            <div key={i} className="flex items-center gap-4">
              <span className="text-2xl">{item.emoji}</span>
              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between mb-1.5">
                  <span className="text-sm font-medium text-gray-800 truncate">{item.name}</span>
                  <div className="flex items-center gap-4 ml-4 flex-shrink-0">
                    <span className="text-xs text-gray-400">{item.orders} orders</span>
                    <span className="text-sm font-bold text-red-600">₹{item.revenue.toLocaleString('en-IN')}</span>
                  </div>
                </div>
                <div className="w-full bg-gray-100 rounded-full h-2">
                  <div
                    className="bg-red-500 h-2 rounded-full transition-all"
                    style={{ width: `${(item.revenue / maxItemRevenue) * 100}%` }}
                  />
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Payment breakdown */}
      <div className="bg-white border border-gray-200 rounded-2xl p-5">
        <h3 className="font-semibold text-gray-900 mb-4">Payment breakdown</h3>
        <div className="grid grid-cols-3 gap-4">
          {[
            { label: 'Online (UPI / Card)', pct: 72, amount: '₹51,408', color: 'bg-blue-500'  },
            { label: 'Cash on delivery',    pct: 20, amount: '₹14,280', color: 'bg-green-500' },
            { label: 'Wallet / Other',      pct: 8,  amount: '₹5,712',  color: 'bg-purple-500' },
          ].map((p, i) => (
            <div key={i} className="text-center">
              <div className="relative w-20 h-20 mx-auto mb-3">
                <svg viewBox="0 0 36 36" className="rotate-[-90deg] w-full h-full">
                  <circle cx="18" cy="18" r="15.9" fill="none" stroke="#f3f4f6" strokeWidth="3.8" />
                  <circle
                    cx="18" cy="18" r="15.9" fill="none"
                    stroke={p.color.replace('bg-', '').replace('-500', '')==='blue'?'#3b82f6':p.color.replace('bg-', '').replace('-500', '')==='green'?'#22c55e':'#a855f7'}
                    strokeWidth="3.8"
                    strokeDasharray={`${p.pct} ${100 - p.pct}`}
                    className={p.color.replace('bg-','stroke-')}
                  />
                </svg>
                <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-base font-bold text-gray-800">{p.pct}%</span>
                </div>
              </div>
              <p className="text-xs text-gray-500 mb-1">{p.label}</p>
              <p className="text-sm font-bold text-gray-800">{p.amount}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
